import React, {useState} from "react";
import './Welcome.css';

function Welcome (props) {
    const [userName, setUserName] = useState('gsfd');
    const [passWord, setPassWord] = useState('sfgd');
    const handleUsernameChange = (e) => {
        const value = e.target.value;
        setUserName(value);
    }
    const Login = () => {console.log('Username: ', userName)};
    function handlePasswordChange (event) {
        setPassWord(props.passWord);
        console.log(event.target.username)
    }
    return  (
    <div class= "welcome-page">
        <h1 class = 'title'>Welcome to Productiv!</h1>
    <form class = 'location-form'>
        <div>
        <label htmlFor="username"> Username </label>
        <input type="text" id="username" name="username" value = {userName} onChange = {handleUsernameChange}></input>
        </div>
        <div>
        <label htmlFor="password"> Password </label>
        <input type="password" id="password" name="password" value = {passWord} onChange = {(e) => setPassWord(e.target.value)}></input>
        </div>
        <div>
        <input type="submit" value= "Log in" onClick={Login}></input>
        </div>
        <div>
        <input type="submit" value= "Sign up"></input>
        </div>
    </form>
    </div>
    )
}

export default Welcome;
